import React, { useState } from 'react';

function Login() {
  const handleLogin = () => {
    localStorage.setItem('token', 'dummy-token');
    window.location.href = '/dashboard';
  };

  return (
    <div>
      <h1>Login</h1>
      <button onClick={handleLogin}>Login</button>
    </div>
  );
}

export default Login;
